11	
12	// A hermetic corpus mirroring the real layout: the REAL engine/hooks/session-start-command.sh
13	// (it self-locates via BASH_SOURCE and resolves the mount-local prefs step
14	// beside itself, the rest one level up at the corpus root) plus tiny STUB
15	// steps, so the test exercises the ORCHESTRATOR's own contract — sequence,
16	// stdout forwarding, lifecycle logging, exit 0 — without dragging in the real
17	// children and their dependencies.
18	function makeCorpus({ prefs = '#!/bin/bash\n', prose = '', skills = '', env = '', interview = '' } = {}) {
19	  const root = mkdtempSync(join(tmpdir(), 'claudinite-sessionstart-'));
20	  mkdirSync(join(root, 'engine', 'hooks'), { recursive: true });
21	  mkdirSync(join(root, 'engine', 'pack_loader'), { recursive: true });
22	  copyFileSync(join(HOOKS_DIR, 'session-start-command.sh'), join(root, 'engine', 'hooks', 'session-start-command.sh'));
23	  mkdirSync(join(root, 'engine', 'hooks', 'steps'), { recursive: true });
24	  writeFileSync(join(root, 'engine', 'hooks', 'steps', 'inject-preferences.sh'), prefs);
25	  writeFileSync(join(root, 'engine', 'pack_loader', 'inject-pack-prose.mjs'), prose);
26	  writeFileSync(join(root, 'engine', 'pack_loader', 'mount-skills.mjs'), skills);
27	  writeFileSync(join(root, 'engine', 'pack_loader', 'env-requirements.mjs'), env);
28	  // The interview machinery is the adoption skill's, bundled in the lifecycle pack.
29	  mkdirSync(join(root, 'packs', 'grow_with_claudinite', 'skills', 'adopt-claudinite'), { recursive: true });
30	  writeFileSync(join(root, 'packs', 'grow_with_claudinite', 'skills', 'adopt-claudinite', 'interview.mjs'), interview);
31	  return root;
32	}
