34	function run(corpus, projectDir, env = {}) {
35	  return spawnSync('bash', [join(corpus, 'engine', 'hooks', 'session-start-command.sh')], {
36	    encoding: 'utf8',
37	    env: { ...process.env, CLAUDE_PROJECT_DIR: projectDir, CLAUDINITE_HOOK_RUN: 'testrun', ...env },
38	  });
39	}
