41	test('orchestrator runs steps in order, forwards only step stdout, logs the lifecycle, exits 0', () => {
42	  const corpus = makeCorpus({
43	    prefs: '#!/bin/bash\necho PREFS\n',
44	    prose: 'process.stdout.write("PROSE\\n");',
45	  });
46	  const projectDir = mkdtempSync(join(tmpdir(), 'claudinite-proj-'));
47	  const r = run(corpus, projectDir);
48	  assert.equal(r.status, 0);
49	  // Only the steps' stdout reaches the hook's stdout (→ session context), in
50	  // order, followed by the one-line confirmation footer; the timestamped log
51	  // goes to stderr + the file, never stdout.
52	  assert.ok(r.stdout.startsWith('PREFS\nPROSE\n'), r.stdout);
53	  assert.match(r.stdout, /^Claudinite session-start: ran 5 steps \(inject-preferences, load-active-prose, mount-skills, env-check, interview-check\) at .+\.$/m);
54	  assert.doesNotMatch(r.stdout, /WARNING/); // all steps exited 0
55	  const log = readFileSync(join(projectDir, '.claudinite-hooks.log'), 'utf8');
56	  for (const s of [
57	    'run=testrun orchestrator: start',
58	    'inject-preferences: start', 'inject-preferences: done exit=0',
59	    'load-active-prose: start', 'load-active-prose: done exit=0',
60	    'mount-skills: start', 'env-check: start', 'interview-check: start',
61	    'run=testrun orchestrator: done',
62	  ]) assert.ok(log.includes(s), `log missing line: ${s}\n--- log ---\n${log}`);
63	});
