68	    prose: 'process.stdout.write("B\\n");', // ...the rest still runs
69	  });
70	  const projectDir = mkdtempSync(join(tmpdir(), 'claudinite-proj-'));
71	  const r = run(corpus, projectDir);
72	  assert.equal(r.status, 0);            // a non-zero SessionStart exit would discard the context
73	  assert.ok(r.stdout.startsWith('A\nB\n'), r.stdout); // later steps still ran and forwarded
74	  // The footer flags the crashed step so a semantic failure is visible in-context.
75	  assert.match(r.stdout, /WARNING: inject-preferences exited 1/);
76	  const log = readFileSync(join(projectDir, '.claudinite-hooks.log'), 'utf8');
77	  assert.ok(log.includes('inject-preferences: done exit=1'), log);
78	});
