90	    encoding: 'utf8',
91	    // An unreachable base forces the fetch path to fail fast and prove fail-soft.
92	    env: { ...process.env, CLAUDE_CODE_USER_EMAIL: email, CLAUDINITE_PREFS_URL: 'https://[REDACTED:env:CLOUDSDK_PROXY_ADDRESS]:1/preferences' },
93	  });
94	
